SELECT member_id, name, email, password, role, created_at, updated_at
FROM member
WHERE email = #{email}

SELECT member_id, name, email, password, role, created_at, updated_at
FROM member
WHERE member_id = #{memberId}

SELECT member_id, name, email, password, role, created_at, updated_at
FROM member
WHERE role = #{role}
